module.render:
const color = args.color || 'var(--accent-color)';
const alignKey = String(args.align || 'center').toLowerCase();
const align = ['left', 'center', 'right'].includes(alignKey) ? alignKey : 'center';
const compact = String(args.compact) === 'true' || String(args.compact) === '1';
const trueC = (args.truecolor || '').trim();
const falseC = (args.falsecolor || '').trim();
const rows = sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean).map((l) => l.split('|').map((c) => c.trim()));
if (!rows.length) return `<div>(truthtable: a header row then rows, columns split by | )</div>`;
const cols = Math.max(...rows.map((r) => r.length));
const cellClass = (v) => {
  const t = v.toLowerCase();
  if (['t','1','true','⊤'].includes(t)) return 'mdp-tt-t';
  if (['f','0','false','⊥'].includes(t)) return 'mdp-tt-f';
  return '';
};
let styleVars = `--tt-color:${color}; --tt-align:${align}; grid-template-columns: repeat(${cols}, auto);`;
if (trueC) styleVars += ` --tt-true:${trueC};`;
if (falseC) styleVars += ` --tt-false:${falseC};`;
const cls = 'mdp-mod-truthtable' + (compact ? ' mdp-tt-compact' : '');
let html = `\n\n<div class="${cls}" style="${styleVars}">`;
rows[0].forEach((c) => { html += `<div class="mdp-tt-cell mdp-tt-head">\n\n${c}\n\n</div>`; });
rows.slice(1).forEach((r) => {
  for (let i = 0; i < cols; i++) {
    const v = r[i] || '';
    html += `<div class="mdp-tt-cell ${cellClass(v)}">\n\n${v}\n\n</div>`;
  }
});
html += `</div>\n\n`;
return html;
